sql:
SELECT AVG(diameter) AS average_diameter
FROM oranges
WHERE weight > 5 AND blemish_level <> 'severe';

SELECT orange_id, COUNT(*) AS num_checks
FROM quality_check_history
GROUP BY orange_id;

SELECT * 
FROM oranges 
WHERE red > (SELECT AVG(red) FROM oranges);

SELECT name FROM oranges
UNION
SELECT alert_message FROM alerts;

SELECT name
FROM oranges
WHERE diameter > (
  SELECT AVG(diameter)
  FROM oranges
);

external_knowledge:
'well-grown oranges with just little imperfections' refers to oranges that are 'ripe' and have 'minor' blemishes;
'heft' refers to the weight of the oranges;
'how they were grown' refers to the production method (organic or conventional);
'farm conditions' include the 'soil type' and 'location';
'who made them and their company' refer to the 'producer' and 'company_name'.

sql:
SELECT name
FROM oranges
WHERE ripeness_level = 'green';

SELECT orange_id
FROM oranges
WHERE diameter < (SELECT AVG(diameter) FROM oranges);

external_knowledge:
- The "garden of failed oranges" refers to the subset of oranges that have failed quality checks;
- The "producer overshadowed by a heavy cloud of disappointment" means the producer whose oranges have failed quality checks, specifically 'Producer 2' in this context;
- The "fruits that have fallen under this shadow" refers to the failed oranges from the specified producer.

sql:
SELECT name, weight 
FROM oranges 
WHERE weight > (SELECT min_value FROM quality_standards WHERE attribute = 'weight');
